sys_config_json:
{
  "models": {
    "vision": {
      "model_id": "Qwen/Qwen3-VL-8B-Instruct",
      "endpoint": "http://localhost:8000/v1",
      "port": 8000,
      "runtime": "vllm-rocm",
      "vram_gb": 16,
      "rocm_flags": "HIP_VISIBLE_DEVICES=0"
    },
    "embedding": {
      "model_id": "Qwen/Qwen3-VL-Embedding-2B",
      "endpoint": "http://localhost:8001/v1", 
      "port": 8001,
      "runtime": "vllm-rocm",
      "vram_gb": 4,
      "rocm_flags": "HIP_VISIBLE_DEVICES=0"
    },
    "coding": {
      "model_id": "qwen2.5-coder:7b",
      "endpoint": "http://localhost:11434",
      "port": 11434,
      "runtime": "ollama",
      "vram_gb": 0,
      "rocm_flags": null
    }
  },
  "paths": {
    "uploads": "/uploads",
    "data": "/data",
    "database": "/data/catmonitor.db",
    "chroma": "/data/chroma",
    "logs": "/data/logs",
    "pid_file": "/data/catmonitor.pid"
  },
  "thresholds": {
    "similarity_known": 0.25,
    "similarity_uncertain": 0.45,
    "confidence_threshold": 0.6,
    "file_stable_seconds": 3,
    "frame_spacing_seconds": 3,
    "max_agent_iterations": 10
  },
  "processing": {
    "frame_width": 640,
    "frame_extraction_fps": 1,
    "top_frames_count": 4,
    "min_score_threshold": 5
  },
  "startup_commands": {
    "vision": "docker run -d --name catmonitor-vision --device=/dev/kfd --device=/dev/dri --group-add=video --ipc=host --cap-add=SYS_PTRACE --security-opt seccomp=unconfined -e HIP_VISIBLE_DEVICES=0 -e ROCM_VERSION=5.7 -p 8000:8000 vllm/vllm-openai:latest --model Qwen/Qwen3-VL-8B-Instruct --max-model-len 16384 --port 8000 --host 0.0.0.0 --enable-auto-tool-choice --tool-call-parser qwen",
    "embedding": "docker run -d --name catmonitor-embedding --device=/dev/kfd --device=/dev/dri --group-add=video --ipc=host --cap-add=SYS_PTRACE --security-opt seccomp=unconfined -e HIP_VISIBLE_DEVICES=0 -e ROCM_VERSION=5.7 -p 8001:8000 vllm/vllm-openai:latest --model Qwen/Qwen3-VL-Embedding-2B --max-model-len 8192 --port 8000 --host 0.0.0.0",
    "coding": "ollama serve"
  },
  "dashboard": {
    "port": 8002,
    "host": "0.0.0.0"
  },
  "logging": {
    "level": "INFO",
    "file": "/data/logs/catmonitor.log",
    "rotation": "daily",
    "retention_days": 14
  }
}
